class Solution:
    def kthSmallestPrimeFraction(self, arr: List[int], k: int) -> List[int]:
        n = len(arr)
        h = [(arr[0]/arr[j], 0, j) for j in range(1, n)]
        heapify(h)
        for _ in range(k-1):
            _, i, j = heappop(h)
            if i + 1 < j:
                heappush(h, (arr[i+1]/arr[j], i+1, j))
        _, i, j = h[0]
        return [arr[i], arr[j]]

